package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.visitor.ModifierVisitor;
import com.github.javaparser.ast.visitor.Visitable;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.Optional;

public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];
        Path directory = Paths.get(sourceDirectory);

        try {
            Files.walk(directory)
                .filter(path -> path.toString().endsWith(".java"))
                .forEach(Main::processJavaFile);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static void processJavaFile(Path filePath) {
        try {
            String content = Files.readString(filePath);
            CompilationUnit cu = StaticJavaParser.parse(content);

            // Apply transformation to replace FilterBuilder.apply() with FilterBuilder.test()
            FilterBuilderApplyReplacer replacer = new FilterBuilderApplyReplacer();
            cu.accept(replacer, null);

            Files.writeString(filePath, cu.toString());
        } catch (Exception e) {
            System.err.println("Error processing " + filePath + ": " + e.getMessage());
        }
    }

    static class FilterBuilderApplyReplacer extends ModifierVisitor<Void> {
        @Override
        public Visitable visit(MethodCallExpr methodCallExpr, Void arg) {
            // Check if this is a call to apply() on FilterBuilder
            if (methodCallExpr.getNameAsString().equals("apply") && 
                methodCallExpr.getScope().isPresent()) {

                // Check if the scope is a FilterBuilder expression
                Optional<MethodCallExpr> scopeMethodCall = methodCallExpr.getScope().asOptional(MethodCallExpr.class);
                if (scopeMethodCall.isPresent()) {
                    MethodCallExpr scope = scopeMethodCall.get();
                    if (scope.getNameAsString().equals("include") || 
                        scope.getNameAsString().equals("exclude") ||
                        scope.getNameAsString().equals("includePackage") ||
                        scope.getNameAsString().equals("excludePackage") ||
                        scope.getNameAsString().equals("includePattern") ||
                        scope.getNameAsString().equals("excludePattern")) {

                        // Replace apply with test
                        methodCallExpr.setName("test");
                    }
                }
            }
            return super.visit(methodCallExpr, arg);
        }
    }
}

